input.function:
() => {
  return {
    url: window.location.href,
    title: document.title,
    bodyText: document.body ? document.body.innerText.substring(0, 500) : 'no body'
  };
}

() => {
  // Cerca tutte le tabelle nella pagina
  const tables = document.querySelectorAll('table');
  const result = [];
  tables.forEach((table, idx) => {
    const rows = table.querySelectorAll('tr');
    const tableData = [];
    rows.forEach(row => {
      const cells = row.querySelectorAll('td, th');
      if (cells.length > 0) {
        tableData.push(Array.from(cells).map(c => c.textContent.trim()));
      }
    });
    if (tableData.length > 0) {
      result.push({tableIndex: idx, rows: tableData.slice(0, 5)});
    }
  });
  return {tableCount: tables.length, tables: result.slice(0, 3)};
}

() => {
  const table = document.querySelector('table');
  if (!table) return {error: 'no table'};
  const rows = table.querySelectorAll('tr');
  const data = [];
  rows.forEach(row => {
    const cells = row.querySelectorAll('td, th');
    if (cells.length > 0) {
      data.push(Array.from(cells).map(c => c.textContent.trim().replace(/\n\t\n\n\n\t\n\t/g, ' | ').replace(/\s+/g, ' ')));
    }
  });
  return {rowCount: data.length, data: data};
}

() => {
  // Cerca il filtro mese - quale è selezionato?
  const allText = document.body.innerText;
  const meseSection = allText.indexOf('Mese Registrazione');
  return allText.substring(meseSection, meseSection + 300);
}
